export type UL = Uint8Array;

export function ulEquals(a: Uint8Array, b: Uint8Array): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return false;
  }
  return true;
}

/** Alias of {@link ulEquals} for generic byte-array comparisons (instance UIDs, etc.). */
export const bytesEqual = ulEquals;

/** Format a UL / byte array as space-separated lowercase hex (e.g. "06 0e 2b 34 …"). */
export function formatUL(u: Uint8Array): string {
  return Array.from(u).map(b => b.toString(16).padStart(2, '0')).join(' ');
}

/**
 * Match two class ULs as metadata Set keys, ignoring the "item designator/version"
 * bytes at positions 5–7 which vary between encoders and spec versions.
 *
 * A UL key for a metadata Set has this structure:
 *   [0-3]  06 0E 2B 34  — Universal Label prefix
 *   [4]    category      — 02 = Sets & Packs
 *   [5]    item type     — 53 = Local Set (2-byte tag/len) — VARIES by encoder
 *   [6-7]  SMPTE version — VARIES by spec version
 *   [8-15] registry UL   — the object identifier, fixed per class
 *
 * We compare [0..4] and [8..15], skip [5..7].
 */
export function ulMatchClass(key: Uint8Array, classUL: Uint8Array): boolean {
  if (key.length < 16 || classUL.length < 16) return false;
  // bytes 0-4: UL prefix + category
  for (let i = 0; i < 5; i++) {
    if (key[i] !== classUL[i]) return false;
  }
  // bytes 8-15: registry object identifier
  for (let i = 8; i < 16; i++) {
    if (key[i] !== classUL[i]) return false;
  }
  return true;
}

export function ulStartsWith(key: Uint8Array, prefix: Uint8Array): boolean {
  if (key.length < prefix.length) return false;
  for (let i = 0; i < prefix.length; i++) {
    if (key[i] !== prefix[i]) return false;
  }
  return true;
}

/**
 * Match a PictureEssenceCoding UL against a prefix, ignoring byte 7 (the SMPTE
 * item-designator / registry-version byte, which varies across spec revisions while
 * the remainder uniquely identifies the codec). Use 0x7f as the placeholder at
 * position 7 in the prefix array — it is never compared.
 */
export function ulMatchEssenceCodingPrefix(ul: Uint8Array, prefix: Uint8Array): boolean {
  if (ul.length < prefix.length) return false;
  for (let i = 0; i < prefix.length; i++) {
    if (i === 7) continue;
    if (ul[i] !== prefix[i]) return false;
  }
  return true;
}

function ul(...bytes: number[]): Uint8Array {
  return new Uint8Array(bytes);
}

// All partition packs share the same first 13 bytes; byte 13 encodes partition type
export const UL_PARTITION_PACK_PREFIX = ul(
  0x06, 0x0e, 0x2b, 0x34, 0x02, 0x05, 0x01, 0x01,
  0x0d, 0x01, 0x02, 0x01, 0x01
);

export const UL_HEADER_PARTITION_OPEN   = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x01,0x01,0x00);
export const UL_HEADER_PARTITION_CLOSED = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x02,0x01,0x00);
export const UL_BODY_PARTITION_OPEN     = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x03,0x01,0x00);
export const UL_BODY_PARTITION_CLOSED   = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x04,0x01,0x00);
export const UL_FOOTER_PARTITION_OPEN   = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x05,0x01,0x00);
export const UL_FOOTER_PARTITION_CLOSED = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x06,0x01,0x00);

// Primer Pack: spec says byte 5 = 0x53 (Local Set encoding), but many encoders write 0x05.
// UL_FOOTER_PARTITION_OPEN and the non-conformant Primer Pack are byte-for-byte identical;
// context (position in file) is the only reliable disambiguator.
export const UL_PRIMER_PACK      = ul(0x06,0x0e,0x2b,0x34,0x02,0x53,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x05,0x01,0x00); // spec-conformant
export const UL_PRIMER_PACK_ALT  = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x05,0x01,0x00); // non-conformant (same bytes as footer open)
// SMPTE ST 377-1 Random Index Pack key: 06 0E 2B 34 02 05 01 01 0D 01 02 01 01 11 01 00.
// (The previous value dropped the byte-12 `01`, shifting the tail, so the RIP — and with it the
// body-partition offsets used to locate essence — was never found in conformant files.)
export const UL_RANDOM_INDEX_PACK = ul(0x06,0x0e,0x2b,0x34,0x02,0x05,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x11,0x01,0x00);

// Index Table Segment — two common variants
export const UL_INDEX_TABLE_SEGMENT_V1 = ul(0x06,0x0e,0x2b,0x34,0x02,0x53,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x10,0x01,0x00);
export const UL_INDEX_TABLE_SEGMENT_V2 = ul(0x06,0x0e,0x2b,0x34,0x02,0x53,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x10,0x02,0x00);

// Filler / KLV fill item
export const UL_KLV_FILL = ul(0x06,0x0e,0x2b,0x34,0x01,0x01,0x01,0x02,0x03,0x01,0x02,0x10,0x01,0x00,0x00,0x00);

// Essence element key prefix (first 4 bytes are always 06 0E 2B 34)
// Essence containers are identified by the UL of the Picture/Sound EssenceCoding
// The generic essence element key prefix is:
export const UL_ESSENCE_ELEMENT_PREFIX = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01);

// Picture Essence Coding ULs (used in descriptors + content package keys)
export const UL_PICTURE_ESSENCE_PREFIX = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01);

// H.264 / AVC essence container labels
export const UL_EC_AVC_BYTE_STREAM     = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01,0x0a,0x0d,0x01,0x03,0x01,0x02,0x10,0x60,0x01);
export const UL_EC_AVC_INTRA_FRAME     = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01,0x0a,0x0d,0x01,0x03,0x01,0x02,0x10,0x60,0x02);

// MPEG-2 essence container labels
export const UL_EC_MPEG2_625_25I_D10   = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01,0x01,0x0d,0x01,0x03,0x01,0x02,0x01,0x01,0x01);
export const UL_EC_MPEG2_LONG_GOP      = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01,0x03,0x0d,0x01,0x03,0x01,0x02,0x04,0x60,0x01);

// PCM audio essence container label
export const UL_EC_GENERIC_SOUND       = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01,0x01,0x0d,0x01,0x03,0x01,0x02,0x06,0x01,0x00);

// Content package essence element key prefixes
// Byte 12 identifies item type:
//   0x05 = SDTI-CP (SMPTE 326M) Picture — used by D-10 / SMPTE 386M
//   0x06 = SDTI-CP Sound (D-10 carries all channels as one AES3 element, byte 14 = 0x10)
//   0x07 = SDTI-CP Data / AUX
//   0x15 = Generic Container (GC) Picture  SMPTE 379M
//   0x16 = Generic Container (GC) Sound    SMPTE 379M
//   0x17 = Generic Container (GC) Data     SMPTE 379M
//   0x18 = D-10 / SMPTE 386M item; byte 14 distinguishes video (0x01) from audio (0x03)
export const UL_CP_PICTURE_ITEM_PREFIX  = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01,0x01,0x0d,0x01,0x03,0x01,0x05);
export const UL_CP_SOUND_ITEM_PREFIX    = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01,0x01,0x0d,0x01,0x03,0x01,0x06);
export const UL_GC_PICTURE_ITEM_PREFIX  = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01,0x01,0x0d,0x01,0x03,0x01,0x15);
export const UL_GC_SOUND_ITEM_PREFIX    = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01,0x01,0x0d,0x01,0x03,0x01,0x16);
export const UL_GC_DATA_ITEM_PREFIX     = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01,0x01,0x0d,0x01,0x03,0x01,0x17);
// D-10 (SMPTE 386M) essence element key prefixes — byte 12 = 0x18
export const UL_D10_VIDEO_ITEM_PREFIX   = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01,0x01,0x0d,0x01,0x03,0x01,0x18,0x01,0x01);
export const UL_D10_SOUND_ITEM_PREFIX   = ul(0x06,0x0e,0x2b,0x34,0x01,0x02,0x01,0x01,0x0d,0x01,0x03,0x01,0x18,0x01,0x03);

// Operational Pattern ULs (prefix shared, last bytes vary)
export const UL_OP1A_PREFIX = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01,0x01,0x0d,0x01,0x02,0x01,0x01,0x01);
export const UL_OP_ATOM_PREFIX = ul(0x06,0x0e,0x2b,0x34,0x04,0x01,0x01,0x02,0x0d,0x01,0x02,0x01,0x10);

export function isPrimerPack(key: Uint8Array): boolean {
  return ulEquals(key, UL_PRIMER_PACK) || ulEquals(key, UL_PRIMER_PACK_ALT);
}

export function isPartitionPack(key: Uint8Array): boolean {
  // Exclude Primer Pack — non-conformant encoders write byte 5 = 0x05, making it
  // share the 13-byte prefix with partition packs.
  if (isPrimerPack(key)) return false;
  return ulStartsWith(key, UL_PARTITION_PACK_PREFIX);
}

export function isEssenceElement(key: Uint8Array): boolean {
  return ulStartsWith(key, UL_GC_PICTURE_ITEM_PREFIX) ||
         ulStartsWith(key, UL_GC_SOUND_ITEM_PREFIX) ||
         ulStartsWith(key, UL_GC_DATA_ITEM_PREFIX);
}

/**
 * True for any MXF Generic Container content-package element: System item (0x04), GC Picture
 * (0x15), Sound (0x16), Data (0x17) or D-10 (0x18). All share bytes [8..11] = 0D 01 03 01
 * ("MXF Generic Container essence"), which uniquely distinguishes a content-package KLV from
 * header metadata (0D 01 01 01), index segments / primer / partition packs (0D 01 02 01 …).
 * Used to find where the essence container actually starts when byte-count math is unreliable.
 */
export function isGenericContainerElement(key: Uint8Array): boolean {
  return key.length >= 12 &&
    key[8] === 0x0d && key[9] === 0x01 && key[10] === 0x03 && key[11] === 0x01;
}

export function isPictureEssence(key: Uint8Array): boolean {
  return ulStartsWith(key, UL_GC_PICTURE_ITEM_PREFIX) ||
         ulStartsWith(key, UL_CP_PICTURE_ITEM_PREFIX) ||
         ulStartsWith(key, UL_D10_VIDEO_ITEM_PREFIX);
}

export function isSoundEssence(key: Uint8Array): boolean {
  return ulStartsWith(key, UL_GC_SOUND_ITEM_PREFIX) ||
         ulStartsWith(key, UL_CP_SOUND_ITEM_PREFIX) ||
         ulStartsWith(key, UL_D10_SOUND_ITEM_PREFIX);
}

/**
 * True for a Generic Container **System Item** — the per-content-package element that carries the
 * frame's SMPTE 12M timecode (among system metadata). Byte 12 is the item-type: 0x04 for the
 * CP-compatible system item (SMPTE 326M, used by D-10) and 0x14 for the GC system item (SMPTE
 * 405M/385M, used by XDCAM/XAVC). Both share the GC essence prefix (bytes [8..11] = 0D 01 03 01).
 */
export function isSystemItem(key: Uint8Array): boolean {
  return isGenericContainerElement(key) && (key[12] === 0x04 || key[12] === 0x14);
}

/**
 * True if a sound essence element is AES3-wrapped (SMPTE 331M, used by D-10): the element is a
 * 4-byte header followed by interleaved 8-channel 32-bit AES3 subframe words (the 24-bit sample
 * sits in bits 4–27). The element-type byte (key[14]) is 0x10 for AES3 vs 0x03 for plain BWF/PCM;
 * SDTI-CP sound items (key[12] === 0x06) are likewise AES3. The decoder unpacks these differently
 * from plain little-endian PCM, so this flag is propagated on each audio EssenceFrame.
 */
export function isAes3Sound(key: Uint8Array): boolean {
  return isSoundEssence(key) && (key[12] === 0x06 || key[14] === 0x10);
}

export function isIndexTableSegment(key: Uint8Array): boolean {
  return ulEquals(key, UL_INDEX_TABLE_SEGMENT_V1) || ulEquals(key, UL_INDEX_TABLE_SEGMENT_V2);
}

export function isFill(key: Uint8Array): boolean {
  return ulEquals(key, UL_KLV_FILL);
}
